USE VACCINE ;-- not run-- not run-- not runDROP TABLE IF EXISTS 入院情報;CREATE TABLE 入院情報 (    ADMISSIONNO VARCHAR(20) NOT NULL,            -- 入院番号    DETAILNO VARCHAR(10) NOT NULL,               -- 詳細番号    PATIENTNO VARCHAR(20) NOT NULL,              -- 患者番号    SEX VARCHAR(1),                              -- 性別    PATIENTAGE INT,                              -- 患者年齢    STARTSTATUS VARCHAR(10),                     -- 開始ステータス    STARTDATE DATE,                              -- 開始日    ENDSTATUS VARCHAR(10),                       -- 終了ステータス    ENDDATE DATE,                                -- 終了日    DEPTCODE VARCHAR(10),                        -- 部署コード    DEPTNAME VARCHAR(50),                        -- 部署名    WARDCODE VARCHAR(10),                        -- 病棟コード    ROOMCODE VARCHAR(10),                        -- 病室コード    ADMISSIONDATE DATE,                          -- 入院日    PURPOSECODE VARCHAR(10),                     -- 目的コード    PURPOSENAME VARCHAR(50),                     -- 目的名    DISFINALDATE DATE,                           -- 退院最終日    DISREASONCODE VARCHAR(10),                   -- 退院理由コード    DISREASONNAME VARCHAR(50)                    -- 退院理由名    -- PRIMARY KEY (ADMISSIONNO, DETAILNO)          -- 入院番号と詳細番号を主キーに設定);LOAD DATA INFILE '/Users/myamaguchi/Data/Vaccin/CH_t02_入院情報_納品.txt'INTO TABLE 入院情報CHARACTER SET sjisFIELDS TERMINATED BY ','ENCLOSED BY '"'LINES TERMINATED BY '\r\n'IGNORE 1 ROWS(    ADMISSIONNO,    DETAILNO,    PATIENTNO,    SEX,    PATIENTAGE,    STARTSTATUS,    @STARTDATE_STR,    ENDSTATUS,    @ENDDATE_STR,    DEPTCODE,    DEPTNAME,    WARDCODE,    ROOMCODE,    @ADMISSIONDATE_STR,    PURPOSECODE,    PURPOSENAME,    @DISFINALDATE_STR,    DISREASONCODE,    DISREASONNAME)SET    STARTDATE = NULLIF(STR_TO_DATE(@STARTDATE_STR, '%Y/%m/%d %H:%i:%s'), ''),    ENDDATE = NULLIF(STR_TO_DATE(@ENDDATE_STR, '%Y/%m/%d %H:%i:%s'), ''),    ADMISSIONDATE = NULLIF(STR_TO_DATE(@ADMISSIONDATE_STR, '%Y/%m/%d %H:%i:%s'), ''),    DISFINALDATE = NULLIF(STR_TO_DATE(@DISFINALDATE_STR, '%Y/%m/%d %H:%i:%s'), '');select * from 入院情報 limit 10;